(function(){'use strict';var PLANS_KEY='efi_action_plans_v1';var EVENTS_KEY='efi_assessment_events_v1';var REFLECTIONS_KEY='efi_reflections_v1';var TOOL_LABELS={module_quiz:'Module Quiz',esqr:'ESQ-R',time_calibrator:'Time Calibrator',task_friction:'Task Friction',ef_story:'EF Profile Story',full_profile:'Full Profile'};var MODULE_LABELS={'module-1':'Module 1: Neuropsychology','module-2':'Module 2: Assessment','module-3':'Module 3: Coaching Architecture','module-4':'Module 4: Applied Methods','module-5':'Module 5: Special Populations','module-6':'Module 6: Ethics'};function readAll(){function parse(key){try{return JSON.parse(localStorage.getItem(key))||[];}catch(e){return[];}}
return{plans:parse(PLANS_KEY),events:parse(EVENTS_KEY),reflections:parse(REFLECTIONS_KEY)};}
function pct(n,d){if(!d)return'\u2014';return Math.round((n/d)*100)+'%';}
function kpiFor(plans,events,reflections){var generated=events.filter(function(e){return e&&e.event_name==='practice_plan_generated';}).length;var started=events.filter(function(e){return e&&e.event_name==='practice_plan_started';}).length;var checkins=events.filter(function(e){return e&&e.event_name==='practice_checkin_completed';}).length;var rechecksDone=events.filter(function(e){return e&&e.event_name==='spaced_recheck_completed';}).length;var transferEvents=events.filter(function(e){return e&&e.event_name==='behavior_transfer_logged';}).length;var masteryEvents=events.filter(function(e){return e&&e.event_name==='mastery_verified';}).length;var activePlans=plans.filter(function(p){return p&&p.state&&p.state.status!=='expired';});var recheckDue=activePlans.filter(function(p){return p.recheck&&p.recheck.due_at;}).length;var reflPlanIds=new Set(reflections.map(function(r){return r&&r.plan_id?r.plan_id:'';}).filter(Boolean));return{generated:generated,activation:pct(started,generated),adherence:pct(checkins,started),recheck:pct(rechecksDone,recheckDue),transfer:pct(reflPlanIds.size,activePlans.length),mastery:pct(masteryEvents,started)};}
function kpiRow(label,k){return{label:label,generated:k.generated,activation:k.activation,adherence:k.adherence,recheck:k.recheck,transfer:k.transfer,mastery:k.mastery};}
function tableWrap(rows,caption){return{rows:rows,caption:caption};}
function operatorSlice(data){var allKpi=kpiFor(data.plans,data.events,data.reflections);var tools=Object.keys(TOOL_LABELS);var rows=[];['authenticated','anonymous'].forEach(function(authState){var isAuth=authState==='authenticated';var authEvents=data.events.filter(function(e){return e&&e.authenticated===isAuth;});if(!authEvents.length)return;var authPlanIds=new Set(authEvents.map(function(e){return e.properties&&e.properties.plan_id?e.properties.plan_id:'';}).filter(Boolean));var authPlans=data.plans.filter(function(p){return p&&authPlanIds.has(p.plan_id);});var authReflections=data.reflections.filter(function(r){return r&&authPlanIds.has(r.plan_id||'');});rows.push(kpiRow((isAuth?'\u{1F512} Authenticated':'\u{1F310} Anonymous'),kpiFor(authPlans,authEvents,authReflections)));});tools.forEach(function(tool){var toolPlans=data.plans.filter(function(p){return p&&p.source_tool===tool;});if(!toolPlans.length)return;var toolEvents=data.events.filter(function(e){return e&&e.properties&&e.properties.source_tool===tool;});var toolReflections=data.reflections.filter(function(r){return r&&r.source_tool===tool;});rows.push(kpiRow(TOOL_LABELS[tool]||tool,kpiFor(toolPlans,toolEvents,toolReflections)));});rows.push({label:'All tools',generated:allKpi.generated,activation:allKpi.activation,adherence:allKpi.adherence,recheck:allKpi.recheck,transfer:allKpi.transfer,mastery:allKpi.mastery,divider:true});return tableWrap(rows.length?rows:[],'KPIs by source tool. Activation = plans started / plans generated. Adherence = check-ins / plans started.');}
function curriculumSlice(data){var modules=Object.keys(MODULE_LABELS);var rows=[];modules.forEach(function(moduleId){var modPlans=data.plans.filter(function(p){return p&&p.source_context&&p.source_context.module_id===moduleId;});if(!modPlans.length)return;var modEvents=data.events.filter(function(e){return e&&e.properties&&(e.properties.module_id===moduleId||e.properties.source_tool==='module_quiz');});var modReflections=data.reflections.filter(function(r){return r&&r.module_id===moduleId;});rows.push(kpiRow(MODULE_LABELS[moduleId]||moduleId,kpiFor(modPlans,modEvents,modReflections)));});return tableWrap(rows,'KPIs by module. Only module_quiz plans are tagged with a specific module_id.');}
function coachingSlice(data){var coachingTools=['esqr','module_quiz'];var rows=[];var adhStates=['Strong adherence','Building consistency','Needs support'];adhStates.forEach(function(label){var statePlans=data.plans.filter(function(p){if(!p||!p.state)return false;var checkins=Array.isArray(p.state.checkins)?p.state.checkins:[];var active=p.state.status!=='expired';var engaged=p.state.status==='started'||p.state.status==='checkin_completed'||p.state.status==='completed';if(!active)return false;if(label==='Strong adherence')return engaged&&checkins.length>=3;if(label==='Building consistency')return engaged&&checkins.length>=1&&checkins.length<3;return!engaged||checkins.length===0;});if(!statePlans.length)return;var planIds=new Set(statePlans.map(function(p){return p.plan_id;}));var stateEvents=data.events.filter(function(e){return e&&e.properties&&e.properties.plan_id&&planIds.has(e.properties.plan_id);});var stateReflections=data.reflections.filter(function(r){return r&&r.plan_id&&planIds.has(r.plan_id);});rows.push(kpiRow(label,kpiFor(statePlans,stateEvents,stateReflections)));});coachingTools.forEach(function(tool){var toolPlans=data.plans.filter(function(p){return p&&p.source_tool===tool;});if(!toolPlans.length)return;var toolEvents=data.events.filter(function(e){return e&&e.properties&&e.properties.source_tool===tool;});var toolReflections=data.reflections.filter(function(r){return r&&r.source_tool===tool;});rows.push(kpiRow((TOOL_LABELS[tool]||tool)+' (tool)',kpiFor(toolPlans,toolEvents,toolReflections)));});return tableWrap(rows,'Adherence-state rows classify individual plans by check-in count. Tool rows show coaching-tool KPIs directly.');}
function renderTabs(container,data){var tabs=[{id:'operator',label:'Operator',content:operatorSlice(data)},{id:'curriculum',label:'Curriculum',content:curriculumSlice(data)},{id:'coaching',label:'Coaching',content:coachingSlice(data)}];while(container.firstChild)container.removeChild(container.firstChild);var title=document.createElement('h2');title.style.marginTop='0';title.textContent='Cohort Analytics';container.appendChild(title);var intro=document.createElement('p');intro.style.color='var(--color-text-light)';intro.textContent='KPI views aggregated from local assessment event and plan data. Values reflect the data in this browser session. Production cohort analytics require server-side aggregation.';container.appendChild(intro);var tabList=document.createElement('div');tabList.className='button-group';tabList.style.marginBottom='var(--space-md)';tabList.setAttribute('role','tablist');container.appendChild(tabList);function renderContentPanel(panel,content){while(panel.firstChild)panel.removeChild(panel.firstChild);if(!content.rows.length){var empty=document.createElement('p');empty.style.color='var(--color-text-muted)';empty.textContent='No data recorded yet.';panel.appendChild(empty);return;}
var caption=document.createElement('p');caption.style.color='var(--color-text-light)';caption.style.fontSize='0.85rem';caption.style.marginBottom='var(--space-sm)';caption.textContent=content.caption;panel.appendChild(caption);var wrap=document.createElement('div');wrap.className='table-wrapper';var table=document.createElement('table');var thead=document.createElement('thead');var headRow=document.createElement('tr');['Slice','Plans','Activation','Adherence','Recheck','Transfer','Mastery'].forEach(function(label){var th=document.createElement('th');th.textContent=label;headRow.appendChild(th);});thead.appendChild(headRow);table.appendChild(thead);var tbody=document.createElement('tbody');content.rows.forEach(function(rowData){var tr=document.createElement('tr');if(rowData.divider)tr.style.borderTop='2px solid var(--color-border)';var labelCell=document.createElement('td');var strong=document.createElement('strong');strong.textContent=rowData.label;labelCell.appendChild(strong);tr.appendChild(labelCell);[rowData.generated,rowData.activation,rowData.adherence,rowData.recheck,rowData.transfer,rowData.mastery].forEach(function(value){var td=document.createElement('td');td.textContent=String(value);tr.appendChild(td);});tbody.appendChild(tr);});table.appendChild(tbody);wrap.appendChild(table);panel.appendChild(wrap);}
tabs.forEach(function(t){var btn=document.createElement('button');btn.type='button';btn.className='btn btn--secondary btn--sm';btn.id='cohort-tab-btn-'+t.id;btn.setAttribute('aria-selected',t.id==='operator'?'true':'false');if(t.id==='operator')btn.style.fontWeight='700';btn.textContent=t.label;tabList.appendChild(btn);var panel=document.createElement('div');panel.id='cohort-panel-'+t.id;panel.setAttribute('role','tabpanel');panel.style.marginTop='var(--space-md)';if(t.id!=='operator')panel.hidden=true;renderContentPanel(panel,t.content);container.appendChild(panel);btn.addEventListener('click',function(){tabs.forEach(function(other){var ob=container.querySelector('#cohort-tab-btn-'+other.id);var op=container.querySelector('#cohort-panel-'+other.id);if(ob){ob.removeAttribute('aria-selected');ob.style.fontWeight='';}
if(op)op.hidden=true;});btn.setAttribute('aria-selected','true');btn.style.fontWeight='700';var panel=container.querySelector('#cohort-panel-'+t.id);if(panel)panel.hidden=false;});});}
function init(){var container=document.getElementById('cohort-analytics-container');if(!container)return;var data=readAll();renderTabs(container,data);}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();